codeChallenges.codigoSeguro:
app.get('/download', (req, res) => {
  const filePath = path.resolve('/uploads', req.query.file);
  if (!filePath.startsWith('/uploads')) {
    return res.status(403).send('Acceso denegado');
  }
  res.sendFile(filePath);
});

